    const int64_t N = sizes[0];
    const int64_t C = sizes[1];
    const int64_t H = sizes[2];
    const int64_t W = sizes[3];
    at::Tensor y = at::empty({N, C, H - 2, W - 2}, x.options());
    EXEC_NPU_CMD(aclnnConvDepthwise2dSquareInputSquareKernelCustom, x, weight, y);
    return y;
